tool_input.new_string:
export function validateToken(token: string): { valid: boolean; reason?: string } {
  if (!token) return { valid: false, reason: 'empty token' };
  if (token.length < 32) return { valid: false, reason: 'token too short' };
  return { valid: true };
}
